import{_ as e}from"./plugin-vue_export-helper-c27b6911.js";import{o as t,c as a,e as o}from"./app-ef36cc2e.js";const r={},n=o('<h1 id="面试-vue" tabindex="-1"><a class="header-anchor" href="#面试-vue" aria-hidden="true">#</a> 面试-Vue</h1><h3 id="谈谈vue生命周期" tabindex="-1"><a class="header-anchor" href="#谈谈vue生命周期" aria-hidden="true">#</a> 谈谈Vue生命周期</h3><details class="hint-container details"><summary><b style="color:#bf3e73;">问：谈谈Vue生命周期</b></summary><p><b style="color:#f19977;">答：Vue的生命周期是指从Vue实例创建、挂载、更新、销毁到最终回收的整个完整过程，核心分为创建（beforeCreate/created）、挂载（beforeMount/mounted）、更新（beforeUpdate/updated）、销毁（beforeUnmount/unmounted）四个阶段：创建阶段完成实例初始化与数据观测，此时el未挂载、DOM不可访问；挂载阶段将实例挂载到指定DOM节点，mounted 钩子中可访问并操作DOM，是发起异步请求、初始化第三方插件的常用时机；更新阶段在响应式数据变化触发重新渲染时执行，可在 beforeUpdate 中获取更新前的 DOM 状态，updated 中获取更新后的 DOM；销毁阶段在实例被销毁时执行，beforeUnmount 中可清理定时器、解绑事件监听等避免内存泄漏，unmounted 时实例与 DOM 完全解绑，所有指令和事件监听失效，整个生命周期由Vue自动驱动，开发者可通过对应钩子函数在不同阶段插入自定义逻辑，且 Vue3 组合式 API 中可通过 setup 结合 onMounted、onUpdated 等函数替代传统选项式钩子，核心生命周期逻辑保持一致</b></p></details>',3),u=[n];function d(s,c){return t(),a("div",null,u)}const f=e(r,[["render",d],["__file","面试-Vue.html.vue"]]);export{f as default};
